// ====================== DATA LAYER ======================
// Local state is persisted in localStorage so the dashboard survives refreshes.
let assets = JSON.parse(localStorage.getItem('spartanburg_assets') || '[]');
let auditLog = JSON.parse(localStorage.getItem('spartanburg_audit') || '[]');
let currentUser = JSON.parse(localStorage.getItem('spartanburg_user') || 'null');
let editingId = null;
let starValue = 3;
let _preEditSnapshot = null; // snapshot before edit for diff

function saveData() {
  localStorage.setItem('spartanburg_assets', JSON.stringify(assets));
}

function saveAuditData() {
  // Keep last 2000 entries to avoid storage bloat
  if (auditLog.length > 2000) auditLog = auditLog.slice(-2000);
  localStorage.setItem('spartanburg_audit', JSON.stringify(auditLog));
}

function genId() {
  return 'AST-' + String(Date.now()).slice(-6);
}

// ====================== USER IDENTITY ======================
// Prefer SharePoint identity when available; otherwise show a guest fallback.
async function detectSharePointUser() {
  try {
    // Try SharePoint REST API for current user
    const res = await fetch('/_api/web/currentUser', {
      headers: { 'Accept': 'application/json;odata=verbose' },
      credentials: 'same-origin'
    });
    if (res.ok) {
      const data = await res.json();
      const u = data.d || data;
      return {
        name: u.Title || u.LoginName || 'SharePoint User',
        email: u.Email || '',
        loginName: u.LoginName || '',
        source: 'sharepoint'
      };
    }
  } catch(e) {}

  // Try SharePoint page context (available in classic pages)
  try {
    if (window._spPageContextInfo) {
      return {
        name: window._spPageContextInfo.userDisplayName || window._spPageContextInfo.userLoginName,
        email: window._spPageContextInfo.userEmail || '',
        loginName: window._spPageContextInfo.userLoginName || '',
        source: 'sharepoint-context'
      };
    }
  } catch(e) {}

  // Try modern SharePoint workbench context
  try {
    if (window.__vtiPageContext) {
      return {
        name: window.__vtiPageContext.userDisplayName || '',
        email: window.__vtiPageContext.userEmail || '',
        loginName: '',
        source: 'sharepoint-modern'
      };
    }
  } catch(e) {}

  return null;
}

async function initUser() {
  const spUser = await detectSharePointUser();
  if (spUser && spUser.name) {
    currentUser = spUser;
    localStorage.setItem('spartanburg_user', JSON.stringify(currentUser));
    renderUserBar();
    return;
  }

  currentUser = { name: 'Guest User', source: 'guest' };
  renderUserBar();
}

function renderUserBar() {
  if (!currentUser) return;
  // Use initials so the user bar stays compact even with long names.
  const initials = currentUser.name.split(' ').map(w => w[0]).join('').slice(0,2).toUpperCase();
  document.getElementById('userAvatar').textContent = initials;
  document.getElementById('userDisplayName').textContent = currentUser.name;
  const meta = currentUser.source === 'sharepoint' || currentUser.source === 'sharepoint-context' || currentUser.source === 'sharepoint-modern'
    ? '✓ Authenticated via SharePoint' : 'Guest access';
  document.getElementById('userBarMeta').textContent = meta;
}

function getUserName() {
  return currentUser ? currentUser.name : 'Unknown User';
}

// ====================== AUDIT LOGGING ======================
// Audit entries capture the before/after state of edits for traceability.
function getFieldLabel(field) {
  const labels = {
    name:'Asset Name', category:'Category', location:'Location/Dept',
    purchaseDate:'Purchase Date', purchaseCost:'Purchase Cost',
    replaceDate:'Replacement Date', replaceCost:'Replacement Cost',
    condition:'Condition', status:'Status', notes:'Notes', rating:'Rating'
  };
  return labels[field] || field;
}

function formatFieldValue(field, val) {
  if (val === null || val === undefined || val === '') return '(empty)';
  if (field === 'purchaseCost' || field === 'replaceCost') {
    const n = parseFloat(val);
    if (!isNaN(n)) return '$' + n.toLocaleString();
  }
  if (field === 'rating') return val + '/5 stars';
  return String(val);
}

function logAudit(action, asset, oldAsset) {
  const entry = {
    id: 'AUD-' + Date.now() + '-' + Math.random().toString(36).slice(2,6),
    action,           // 'ADD' | 'EDIT' | 'DELETE' | 'IMPORT'
    assetId: asset ? asset.id : null,
    assetName: asset ? asset.name : null,
    assetTag: asset ? asset.assetId : null,
    user: getUserName(),
    userEmail: currentUser ? (currentUser.email || '') : '',
    timestamp: new Date().toISOString(),
    changes: []       // array of {field, oldVal, newVal}
  };

  if (action === 'EDIT' && oldAsset) {
    // Only store edit records when one of the tracked fields changed.
    const trackedFields = ['name','category','location','condition','status','rating',
      'purchaseDate','purchaseCost','replaceDate','replaceCost','notes'];
    trackedFields.forEach(field => {
      const oldVal = String(oldAsset[field] ?? '');
      const newVal = String(asset[field] ?? '');
      if (oldVal !== newVal) {
        entry.changes.push({ field, oldVal, newVal });
      }
    });
    // If nothing changed, don't log
    if (entry.changes.length === 0) return;
  }

  auditLog.unshift(entry);
  saveAuditData();
}

function logBulkImport(count, updated) {
  const entry = {
    id: 'AUD-' + Date.now(),
    action: 'IMPORT',
    assetId: null,
    assetName: `Bulk Import: ${count} added, ${updated} updated`,
    assetTag: null,
    user: getUserName(),
    userEmail: currentUser ? (currentUser.email || '') : '',
    timestamp: new Date().toISOString(),
    changes: []
  };
  auditLog.unshift(entry);
  saveAuditData();
}

// ====================== NAVIGATION ======================
// Switch the visible page, then refresh shared widgets to keep filters in sync.
function showPage(name, el) {
  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  document.querySelectorAll('.nav-tab').forEach(t => t.classList.remove('active'));
  document.getElementById('page-' + name).classList.add('active');
  if (el) el.classList.add('active');
  refreshAll();
}

// ====================== DATE ======================
// Header date is set once at load so the chrome feels current without polling.
function setDate() {
  const d = new Date();
  document.getElementById('headerDate').textContent = d.toLocaleDateString('en-US', { weekday:'short', month:'short', day:'numeric', year:'numeric' });
}
setDate();

// ====================== MODAL ======================
// The editor modal is reused for both create and edit flows.
function openAddAsset() {
  editingId = null;
  document.getElementById('modalTitle').textContent = 'Add New Asset';
  clearForm();
  document.getElementById('assetModal').classList.add('open');
}

function openEditAsset(id) {
  const a = assets.find(x => x.id === id);
  if (!a) return;
  editingId = id;
  // Snapshot the asset BEFORE edit so we can diff on save
  _preEditSnapshot = JSON.parse(JSON.stringify(a));
  document.getElementById('modalTitle').textContent = 'Edit Asset';
  document.getElementById('fName').value = a.name;
  document.getElementById('fId').value = a.assetId;
  document.getElementById('fCategory').value = a.category;
  document.getElementById('fLocation').value = a.location;
  document.getElementById('fPurchaseDate').value = a.purchaseDate;
  document.getElementById('fPurchaseCost').value = a.purchaseCost;
  document.getElementById('fReplaceDate').value = a.replaceDate;
  document.getElementById('fReplaceCost').value = a.replaceCost;
  document.getElementById('fCondition').value = a.condition;
  document.getElementById('fStatus').value = a.status;
  document.getElementById('fNotes').value = a.notes;
  setStars(a.rating || 3);
  document.getElementById('assetModal').classList.add('open');
  closeDetailModal();
}

function closeModal() {
  document.getElementById('assetModal').classList.remove('open');
}

function closeDetailModal() {
  document.getElementById('detailModal').classList.remove('open');
}

function clearForm() {
  ['fName','fId','fLocation','fPurchaseDate','fPurchaseCost','fReplaceDate','fReplaceCost','fNotes'].forEach(id => document.getElementById(id).value = '');
  document.getElementById('fCategory').value = '';
  document.getElementById('fCondition').value = 'Good';
  document.getElementById('fStatus').value = 'Active';
  setStars(3);
}

// ====================== STARS ======================
// Rating stars are stored separately so hover and click interactions stay simple.
function setStars(val) {
  starValue = val;
  document.querySelectorAll('#starRating .star').forEach((s, i) => {
    s.classList.toggle('on', i < val);
  });
}

document.querySelectorAll('#starRating .star').forEach(s => {
  s.addEventListener('click', () => setStars(parseInt(s.dataset.val)));
  s.addEventListener('mouseover', () => {
    document.querySelectorAll('#starRating .star').forEach((x, i) => x.classList.toggle('on', i < parseInt(s.dataset.val)));
  });
});
document.getElementById('starRating').addEventListener('mouseleave', () => setStars(starValue));

// ====================== SAVE ASSET ======================
// Validate required fields, persist the asset, and write the audit record together.
function saveAsset() {
  const name = document.getElementById('fName').value.trim();
  const category = document.getElementById('fCategory').value;
  if (!name) { alert('Please enter an asset name.'); return; }
  if (!category) { alert('Please select a category.'); return; }

  const asset = {
    id: editingId || genId(),
    assetId: document.getElementById('fId').value.trim() || genId(),
    name,
    category,
    location: document.getElementById('fLocation').value.trim(),
    purchaseDate: document.getElementById('fPurchaseDate').value,
    purchaseCost: parseFloat(document.getElementById('fPurchaseCost').value) || 0,
    replaceDate: document.getElementById('fReplaceDate').value,
    replaceCost: parseFloat(document.getElementById('fReplaceCost').value) || 0,
    condition: document.getElementById('fCondition').value,
    status: document.getElementById('fStatus').value,
    notes: document.getElementById('fNotes').value.trim(),
    rating: starValue,
    updatedAt: new Date().toISOString()
  };

  if (editingId) {
    const idx = assets.findIndex(x => x.id === editingId);
    logAudit('EDIT', asset, _preEditSnapshot);
    assets[idx] = asset;
    _preEditSnapshot = null;
  } else {
    assets.unshift(asset);
    logAudit('ADD', asset, null);
  }

  saveData();
  closeModal();
  refreshAll();
}

// ====================== DELETE ======================
function deleteAsset(id) {
  if (!confirm('Delete this asset? This cannot be undone.')) return;
  const deleted = assets.find(x => x.id === id);
  if (deleted) logAudit('DELETE', deleted, null);
  assets = assets.filter(x => x.id !== id);
  saveData();
  closeDetailModal();
  refreshAll();
}

// ====================== DETAIL VIEW ======================
// Build a rich read-only summary with quick access to edit, delete, and history.
function showDetail(id) {
  const a = assets.find(x => x.id === id);
  if (!a) return;
  document.getElementById('detailTitle').textContent = a.name;
  document.getElementById('detailEditBtn').onclick = () => openEditAsset(id);

  const condColor = { Good: '#1e7b4b', Fair: '#9a6b00', Poor: '#c0392b', Critical: '#8b0000' };
  const stars = '★'.repeat(a.rating || 0) + '☆'.repeat(5 - (a.rating || 0));
  const yearsLeft = a.replaceDate ? Math.ceil((new Date(a.replaceDate) - new Date()) / (365.25 * 24 * 3600 * 1000)) : null;

  // Find last audit entry for this asset
  const lastEdit = auditLog.find(e => e.assetId === id);
  const lastEditHtml = lastEdit
    ? `<div style="background:#f0f4f8;border-radius:7px;padding:10px 14px;font-size:11px;color:var(--text-mid);margin-bottom:12px;">
        <strong style="color:var(--navy);">${lastEdit.action === 'ADD' ? '➕ Created' : '✏️ Last edited'}</strong> by
        <strong>${lastEdit.user}</strong>${lastEdit.userEmail ? ' (' + lastEdit.userEmail + ')' : ''}
        · ${new Date(lastEdit.timestamp).toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'})}
        at ${new Date(lastEdit.timestamp).toLocaleTimeString('en-US',{hour:'numeric',minute:'2-digit'})}
        <span style="margin-left:8px;cursor:pointer;color:var(--navy-light);text-decoration:underline;"
          onclick="closeDetailModal();showPage('auditlog', document.querySelectorAll('.nav-tab')[7]);document.getElementById('auditSearch').value='${a.name.replace(/'/g,"\\'")}';renderAuditLog();">
          View history →
        </span>
      </div>`
    : '';

  document.getElementById('detailBody').innerHTML = lastEditHtml + `
    <div style="display:flex;gap:10px;margin-bottom:16px;flex-wrap:wrap;">
      ${condTag(a.condition)}
      <span class="tag tag-blue">${a.category}</span>
      <span class="tag" style="background:#f0f2f6;color:var(--text-mid)">${a.status}</span>
    </div>
    <div class="detail-grid">
      <div class="detail-item"><div class="detail-label">Asset ID</div><div class="detail-val" style="font-family:'DM Mono',monospace">${a.assetId}</div></div>
      <div class="detail-item"><div class="detail-label">Location</div><div class="detail-val">${a.location || '—'}</div></div>
      <div class="detail-item"><div class="detail-label">Purchase Date</div><div class="detail-val">${a.purchaseDate ? fmtDate(a.purchaseDate) : '—'}</div></div>
      <div class="detail-item"><div class="detail-label">Purchase Cost</div><div class="detail-val">${a.purchaseCost ? fmtCurrency(a.purchaseCost) : '—'}</div></div>
      <div class="detail-item"><div class="detail-label">Replacement Date</div><div class="detail-val" style="color:${yearsLeft !== null && yearsLeft < 0 ? 'var(--red)' : yearsLeft !== null && yearsLeft < 2 ? 'var(--amber)' : 'var(--navy)'}">${a.replaceDate ? fmtDate(a.replaceDate) : '—'}${yearsLeft !== null ? ` <span style="font-size:11px;font-weight:400;color:var(--text-mid)">(${yearsLeft < 0 ? Math.abs(yearsLeft) + ' yr(s) overdue' : yearsLeft + ' yr(s) away'})</span>` : ''}</div></div>
      <div class="detail-item"><div class="detail-label">Est. Replacement Cost</div><div class="detail-val" style="color:var(--teal)">${a.replaceCost ? fmtCurrency(a.replaceCost) : '—'}</div></div>
      <div class="detail-item full" style="grid-column:1/-1"><div class="detail-label">Condition Rating</div><div class="detail-val" style="color:var(--gold);font-size:20px;letter-spacing:2px">${stars} <span style="font-size:13px;color:var(--text-mid)">${a.rating}/5</span></div></div>
      ${a.notes ? `<div class="detail-item full" style="grid-column:1/-1"><div class="detail-label">Notes</div><div class="detail-val" style="font-weight:400;font-size:13px;line-height:1.5">${a.notes}</div></div>` : ''}
    </div>
    <div style="margin-top:16px;display:flex;gap:8px;">
      <button onclick="deleteAsset('${id}')" style="background:#fdecea;color:#c0392b;border:none;padding:8px 16px;border-radius:6px;font-family:'DM Sans',sans-serif;font-size:13px;font-weight:600;cursor:pointer;">🗑 Delete Asset</button>
    </div>
  `;
  document.getElementById('detailModal').classList.add('open');
}

// ====================== FILTERS ======================
// Keep table search fast by filtering in-memory before re-rendering the list.
function filterAssets() {
  const q = document.getElementById('searchInput').value.toLowerCase();
  const cat = document.getElementById('filterCategory').value;
  const cond = document.getElementById('filterCondition').value;
  const status = document.getElementById('filterStatus').value;
  const dept = document.getElementById('filterDept') ? document.getElementById('filterDept').value : '';
  const filtered = assets.filter(a =>
    (!q || a.name.toLowerCase().includes(q) || a.assetId.toLowerCase().includes(q) || (a.location||'').toLowerCase().includes(q)) &&
    (!cat || a.category === cat) &&
    (!cond || a.condition === cond) &&
    (!status || a.status === status) &&
    (!dept || (a.location||'').includes(dept))
  );
  renderAssetTable(filtered);
  document.getElementById('assetCount').textContent = `Showing ${filtered.length} of ${assets.length} assets`;
}

// ====================== RENDERS ======================
// Shared rendering helpers keep condition and currency formatting consistent.
function condTag(c) {
  const cls = { Good: 'tag-good', Fair: 'tag-fair', Poor: 'tag-poor', Critical: 'tag-critical' };
  const icons = { Good: '✅', Fair: '🟡', Poor: '🔴', Critical: '⛔' };
  return `<span class="tag ${cls[c] || 'tag-fair'}">${icons[c] || ''} ${c}</span>`;
}

function condBar(val) {
  const pct = (val / 5) * 100;
  const color = val >= 4 ? '#27ae60' : val >= 3 ? '#e8b04a' : val >= 2 ? '#e67e22' : '#c0392b';
  return `<div class="cond-bar"><div class="cond-track"><div class="cond-fill" style="width:${pct}%;background:${color}"></div></div><div class="cond-num" style="color:${color}">${val}/5</div></div>`;
}

function fmtCurrency(n) {
  if (n >= 1000000) return '$' + (n / 1000000).toFixed(1) + 'M';
  if (n >= 1000) return '$' + Math.round(n / 1000) + 'K';
  return '$' + n.toLocaleString();
}

function fmtDate(d) {
  if (!d) return '—';
  const [y, m, day] = d.split('-');
  return `${m}/${day}/${y}`;
}

function getReplacementStatus(asset, now = new Date()) {
  if (!asset.replaceDate) return { label: 'Planned', level: 'planned', days: null };
  const days = Math.ceil((new Date(asset.replaceDate) - now) / (24 * 3600 * 1000));
  if (days < 0) return { label: 'Overdue', level: 'urgent', days };
  if (days < 180) return { label: 'Soon', level: 'soon', days };
  if (days < 365) return { label: 'Planned', level: 'planned', days };
  return { label: 'Future', level: 'planned', days };
}

function getYearLabel(currentYear, year) {
  if (year < currentYear) return `${currentYear - year} yr${currentYear - year === 1 ? '' : 's'} past`;
  if (year === currentYear) return 'Current year';
  if (year === currentYear + 1) return 'Next year';
  return `FY ${year}`;
}

function renderAssetTable(list) {
  const tbody = document.getElementById('assetTableBody');
  if (!list || !list.length) {
    tbody.innerHTML = '<tr><td colspan="11"><div class="empty"><div class="empty-icon">🗂</div><div class="empty-text">No assets match your filters.</div></div></td></tr>';
    return;
  }
  tbody.innerHTML = list.map(a => {
    const overdue = a.replaceDate && new Date(a.replaceDate) < new Date();
    return `<tr onclick="showDetail('${a.id}')">
      <td><span style="font-family:'DM Mono',monospace;font-size:12px;color:var(--text-light)">${a.assetId}</span></td>
      <td><strong>${a.name}</strong></td>
      <td><span class="tag tag-blue">${a.category}</span></td>
      <td>${a.location || '—'}</td>
      <td>${condTag(a.condition)}</td>
      <td>${condBar(a.rating || 0)}</td>
      <td style="font-size:12px">${a.purchaseDate ? fmtDate(a.purchaseDate) : '—'}</td>
      <td style="font-size:12px;color:${overdue ? 'var(--red)' : 'var(--text)'};font-weight:${overdue ? '600' : '400'}">${a.replaceDate ? fmtDate(a.replaceDate) : '—'}${overdue ? ' ⚠️' : ''}</td>
      <td style="font-family:'DM Mono',monospace;font-size:13px;font-weight:600;color:var(--teal)">${a.replaceCost ? fmtCurrency(a.replaceCost) : '—'}</td>
      <td><span class="tag" style="background:#f0f2f6;color:var(--text-mid)">${a.status}</span></td>
      <td onclick="event.stopPropagation()">
        <button onclick="openEditAsset('${a.id}')" style="background:none;border:none;cursor:pointer;font-size:14px;padding:4px 6px;border-radius:4px" title="Edit">✏️</button>
        <button onclick="deleteAsset('${a.id}')" style="background:none;border:none;cursor:pointer;font-size:14px;padding:4px 6px;border-radius:4px" title="Delete">🗑</button>
      </td>
    </tr>`;
  }).join('');
}

function refreshDashboard() {
  // Dashboard widgets summarize the current asset set at a glance.
  const now = new Date();
  const in2yr = new Date(); in2yr.setFullYear(in2yr.getFullYear() + 2);
  const in5yr = new Date(); in5yr.setFullYear(in5yr.getFullYear() + 5);

  const total = assets.length;
  const cats = [...new Set(assets.map(a => a.category))].length;
  const critical = assets.filter(a => a.condition === 'Critical' || a.condition === 'Poor').length;
  const due2 = assets.filter(a => a.replaceDate && new Date(a.replaceDate) <= in2yr);
  const due2cost = due2.reduce((s, a) => s + (a.replaceCost || 0), 0);
  const due5cost = assets.filter(a => a.replaceDate && new Date(a.replaceDate) <= in5yr).reduce((s, a) => s + (a.replaceCost || 0), 0);

  document.getElementById('kpiTotal').textContent = total;
  document.getElementById('kpiCats').textContent = cats;
  document.getElementById('kpiCritical').textContent = critical;
  document.getElementById('kpiDue').textContent = due2.length;
  document.getElementById('kpiDueCost').textContent = fmtCurrency(due2cost);
  document.getElementById('kpi5yr').textContent = fmtCurrency(due5cost);

  // Condition donut
  const condCounts = { Good: 0, Fair: 0, Poor: 0, Critical: 0 };
  assets.forEach(a => { if (condCounts[a.condition] !== undefined) condCounts[a.condition]++; });
  const condColors = { Good: '#27ae60', Fair: '#e8b04a', Poor: '#e67e22', Critical: '#c0392b' };
  const totalC = Object.values(condCounts).reduce((s, v) => s + v, 0);
  const donutEl = document.getElementById('conditionDonut');
  if (!totalC) {
    donutEl.innerHTML = '<div class="empty"><div class="empty-icon">📊</div><div class="empty-text">Add assets to see condition overview</div></div>';
  } else {
    let offset = 0;
    const r = 60, cx = 80, cy = 80, strokeW = 22;
    const circ = 2 * Math.PI * r;
    let segments = '';
    Object.entries(condCounts).forEach(([k, v]) => {
      if (!v) return;
      const pct = v / totalC;
      const dash = pct * circ;
      segments += `<circle cx="${cx}" cy="${cy}" r="${r}" fill="none" stroke="${condColors[k]}" stroke-width="${strokeW}" stroke-dasharray="${dash} ${circ - dash}" stroke-dashoffset="${-(offset * circ)}" transform="rotate(-90 ${cx} ${cy})" />`;
      offset += pct;
    });
    const legendItems = Object.entries(condCounts).filter(([,v]) => v > 0).map(([k, v]) =>
      `<div class="legend-item"><div class="legend-dot" style="background:${condColors[k]}"></div><span style="flex:1">${k}</span><strong>${v}</strong></div>`
    ).join('');
    donutEl.innerHTML = `<div class="donut-wrap">
      <svg class="donut-svg" width="160" height="160" viewBox="0 0 160 160">
        ${segments}
        <text x="${cx}" y="${cy - 6}" text-anchor="middle" font-size="22" font-weight="700" fill="#0d2240">${total}</text>
        <text x="${cx}" y="${cy + 12}" text-anchor="middle" font-size="10" fill="#8a9bb8">ASSETS</text>
      </svg>
      <div class="donut-legend">${legendItems}</div>
    </div>`;
  }

  // Upcoming replacements are rendered in date order so urgency is obvious.
  const upcoming = assets.filter(a => a.replaceDate).sort((a, b) => new Date(a.replaceDate) - new Date(b.replaceDate)).slice(0, 5);
  const upEl = document.getElementById('upcomingList');
  if (!upcoming.length) {
    upEl.innerHTML = '<div class="empty"><div class="empty-icon">🔄</div><div class="empty-text">No upcoming replacements scheduled</div></div>';
  } else {
    const icons = { 'Fleet Vehicles': '🚗', 'Buildings & Facilities': '🏢', 'IT Equipment': '💻', 'Parks & Recreation': '🌳', 'Public Safety': '🚨', 'Roads & Infrastructure': '🛣️', 'Utilities': '⚡', 'Other': '📦' };
    upEl.innerHTML = '<div class="timeline">' + upcoming.map(a => {
      const days = Math.ceil((new Date(a.replaceDate) - now) / (24 * 3600 * 1000));
      const cls = days < 0 ? 'urgent' : days < 365 ? 'soon' : 'planned';
      return `<div class="tl-item ${cls}" onclick="showDetail('${a.id}')" style="cursor:pointer">
        <div class="tl-icon">${icons[a.category] || '📦'}</div>
        <div class="tl-info">
          <div class="tl-name">${a.name}</div>
          <div class="tl-meta">${a.category} · ${days < 0 ? Math.abs(days) + ' days overdue' : days < 365 ? 'In ' + days + ' days' : fmtDate(a.replaceDate)}</div>
        </div>
        <div class="tl-cost">${a.replaceCost ? fmtCurrency(a.replaceCost) : '—'}</div>
      </div>`;
    }).join('') + '</div>';
  }

  // Category spend is shown as a simple horizontal ranking instead of a chart library.
  const catCosts = {};
  assets.forEach(a => { catCosts[a.category] = (catCosts[a.category] || 0) + (a.replaceCost || 0); });
  const catEl = document.getElementById('categoryChart');
  const catEntries = Object.entries(catCosts).filter(([,v]) => v > 0).sort((a, b) => b[1] - a[1]);
  if (!catEntries.length) {
    catEl.innerHTML = '<div class="empty"><div class="empty-icon">📊</div><div class="empty-text">Add assets to see cost breakdown</div></div>';
  } else {
    const maxCat = Math.max(...catEntries.map(([,v]) => v));
    const catColors = ['#163354','#1e4a7a','#c8922a','#1a7a6e','#8b3a3a','#4a5e7a','#22a090','#e8b04a'];
    catEl.innerHTML = catEntries.slice(0, 6).map(([k, v], i) => `
      <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;">
        <div style="width:120px;font-size:12px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;color:var(--text-mid)">${k}</div>
        <div style="flex:1;height:10px;background:#e8ecf3;border-radius:5px;overflow:hidden">
          <div style="width:${(v/maxCat)*100}%;height:100%;background:${catColors[i % catColors.length]};border-radius:5px;transition:width 0.5s ease"></div>
        </div>
        <div style="font-family:'DM Mono',monospace;font-size:12px;font-weight:600;color:var(--navy);width:60px;text-align:right">${fmtCurrency(v)}</div>
      </div>
    `).join('');
  }

  // Recent activity is derived from the latest updatedAt timestamps.
  const recentEl = document.getElementById('recentActivity');
  const recent = [...assets].sort((a, b) => new Date(b.updatedAt) - new Date(a.updatedAt)).slice(0, 5);
  if (!recent.length) {
    recentEl.innerHTML = '<div class="empty"><div class="empty-icon">📋</div><div class="empty-text">No recent activity</div></div>';
  } else {
    recentEl.innerHTML = recent.map(a => `
      <div onclick="showDetail('${a.id}')" style="display:flex;align-items:center;gap:12px;padding:10px 0;border-bottom:1px solid #f0f2f6;cursor:pointer">
        <div style="width:36px;height:36px;border-radius:8px;background:#f0f4fa;display:flex;align-items:center;justify-content:center;font-size:16px">📋</div>
        <div style="flex:1">
          <div style="font-size:13px;font-weight:600">${a.name}</div>
          <div style="font-size:11px;color:var(--text-light)">${a.category} · Updated ${new Date(a.updatedAt).toLocaleDateString()}</div>
        </div>
        ${condTag(a.condition)}
      </div>
    `).join('');
  }
}

function refreshProjections() {
  const now = new Date();
  const currentYear = now.getFullYear();
  const years = Array.from({length: 7}, (_, i) => currentYear + i);

  const byYear = {};
  years.forEach(y => { byYear[y] = []; });
  assets.forEach(a => {
    if (!a.replaceDate) return;
    const year = new Date(a.replaceDate).getFullYear();
    if (byYear[year]) byYear[year].push(a);
  });

  const yearStats = years.map(year => {
    const items = byYear[year];
    const total = items.reduce((sum, a) => sum + (a.replaceCost || 0), 0);
    return {
      year,
      items,
      total,
      count: items.length,
      overdue: items.filter(a => new Date(a.replaceDate) < now).length,
      critical: items.filter(a => a.condition === 'Critical' || a.condition === 'Poor').length
    };
  });

  const projBarsEl = document.getElementById('projectionBars');
  const totalForecast = yearStats.reduce((sum, row) => sum + row.total, 0);
  const next3Years = yearStats.slice(0, 3).reduce((sum, row) => sum + row.total, 0);
  const overdueForecast = yearStats.filter(row => row.year < currentYear).reduce((sum, row) => sum + row.total, 0);
  const peakYear = yearStats.reduce((best, row) => row.total > best.total ? row : best, yearStats[0]);
  if (!yearStats.some(row => row.total > 0)) {
    projBarsEl.innerHTML = '<div class="empty"><div class="empty-icon">📈</div><div class="empty-text">Add assets with replacement dates to see projections</div></div>';
  } else {
    const maxY = Math.max(...yearStats.map(row => row.total), 1);
    projBarsEl.innerHTML = `
      <div class="forecast-summary">
        <div class="forecast-stat red">
          <div class="forecast-stat-label">Overdue in forecast window</div>
          <div class="forecast-stat-value">${fmtCurrency(overdueForecast)}</div>
          <div class="forecast-stat-sub">${yearStats.filter(row => row.year < currentYear).reduce((sum, row) => sum + row.count, 0)} assets</div>
        </div>
        <div class="forecast-stat gold">
          <div class="forecast-stat-label">Next 3 years</div>
          <div class="forecast-stat-value">${fmtCurrency(next3Years)}</div>
          <div class="forecast-stat-sub">${yearStats.slice(0, 3).reduce((sum, row) => sum + row.count, 0)} assets</div>
        </div>
        <div class="forecast-stat teal">
          <div class="forecast-stat-label">7-year total</div>
          <div class="forecast-stat-value">${fmtCurrency(totalForecast)}</div>
          <div class="forecast-stat-sub">Peak year ${peakYear.year} · ${fmtCurrency(peakYear.total)}</div>
        </div>
      </div>
      <div class="forecast-grid">
        ${yearStats.map((row, index) => {
          const pct = row.total ? (row.total / maxY) * 100 : 0;
          const delta = index > 0 ? row.total - yearStats[index - 1].total : 0;
          const deltaLabel = index > 0 ? `${delta >= 0 ? '▲' : '▼'} ${fmtCurrency(Math.abs(delta))}` : 'Baseline';
          const yearLevel = row.year < currentYear ? 'past' : row.year === currentYear ? 'current' : row.year <= currentYear + 2 ? 'near' : 'future';
          return `<div class="forecast-year-card ${yearLevel}">
            <div class="forecast-year-head">
              <div>
                <div class="forecast-year">${row.year}</div>
                <div class="forecast-year-label">${getYearLabel(currentYear, row.year)}</div>
              </div>
              <div class="forecast-pill ${row.overdue ? 'urgent' : row.critical ? 'soon' : 'planned'}">${row.count} asset${row.count === 1 ? '' : 's'}</div>
            </div>
            <div class="forecast-year-value">${row.total ? fmtCurrency(row.total) : '—'}</div>
            <div class="forecast-year-sub">${row.overdue ? `${row.overdue} overdue` : row.critical ? `${row.critical} high risk` : `${row.items.length} scheduled`}</div>
            <div class="forecast-year-track"><div class="forecast-year-fill ${row.overdue ? 'urgent' : row.critical ? 'soon' : 'planned'}" style="width:${Math.max(pct, row.total ? 8 : 0)}%"></div></div>
            <div class="forecast-year-foot">${deltaLabel}</div>
          </div>`;
        }).join('')}
      </div>
    `;
  }

  // Category breakdown for projections
  const catBrkEl = document.getElementById('projCategoryBreakdown');
  const catTotals = {};
  const catCounts = {};
  assets.forEach(a => {
    if (!a.replaceDate || !a.replaceCost) return;
    catTotals[a.category] = (catTotals[a.category] || 0) + a.replaceCost;
    catCounts[a.category] = (catCounts[a.category] || 0) + 1;
  });
  const catEntries = Object.entries(catTotals).sort((a, b) => b[1] - a[1]);
  if (!catEntries.length) {
    catBrkEl.innerHTML = '<div class="empty"><div class="empty-icon">📊</div><div class="empty-text">Add assets to see breakdown</div></div>';
  } else {
    const grandTotal = catEntries.reduce((sum, [,v]) => sum + v, 0);
    const dominant = catEntries[0];
    catBrkEl.innerHTML = `
      <div class="breakdown-summary">Largest exposure: <strong>${dominant[0]}</strong> at ${fmtCurrency(dominant[1])}</div>
      <div class="breakdown-list">
        ${catEntries.map(([category, value]) => {
          const pct = ((value / grandTotal) * 100).toFixed(1);
          return `<div class="breakdown-row">
            <div class="breakdown-head">
              <div class="breakdown-name">${category}</div>
              <div class="breakdown-meta">${catCounts[category]} asset${catCounts[category] === 1 ? '' : 's'} · ${pct}%</div>
            </div>
            <div class="breakdown-track"><div class="breakdown-fill" style="width:${pct}%"></div></div>
            <div class="breakdown-total">${fmtCurrency(value)}</div>
          </div>`;
        }).join('')}
      </div>
      <div class="breakdown-footer"><span>Total</span><strong>${fmtCurrency(grandTotal)}</strong></div>
    `;
  }

  // Projection table
  const tbody = document.getElementById('projTableBody');
  const projAssets = assets.filter(a => a.replaceDate).sort((a, b) => new Date(a.replaceDate) - new Date(b.replaceDate));
  if (!projAssets.length) {
    tbody.innerHTML = '<tr><td colspan="6"><div class="empty"><div class="empty-icon">📋</div><div class="empty-text">No projection data available</div></div></td></tr>';
  } else {
    tbody.innerHTML = projAssets.map(a => {
      const y = new Date(a.replaceDate).getFullYear();
      const status = getReplacementStatus(a, now);
      const priority = status.level === 'urgent' ? '<span class="tag tag-critical">Overdue</span>' : a.condition === 'Critical' ? '<span class="tag tag-critical">Critical</span>' : a.condition === 'Poor' || status.level === 'soon' ? '<span class="tag tag-poor">High</span>' : '<span class="tag tag-good">Normal</span>';
      return `<tr onclick="showDetail('${a.id}')" style="cursor:pointer">
        <td style="font-family:'DM Mono',monospace;font-weight:600">${y}</td>
        <td><strong>${a.name}</strong></td>
        <td><span class="tag tag-blue">${a.category}</span></td>
        <td>${condTag(a.condition)}</td>
        <td style="font-family:'DM Mono',monospace;font-weight:600;color:var(--teal)">${a.replaceCost ? fmtCurrency(a.replaceCost) : '—'}</td>
        <td>${priority}</td>
      </tr>`;
    }).join('');
  }
}

function renderReplacements() {
  const yearF = document.getElementById('replYearFilter').value;
  const catF = document.getElementById('replCatFilter').value;
  let list = assets.filter(a => a.replaceDate);
  if (yearF) list = list.filter(a => new Date(a.replaceDate).getFullYear() == yearF);
  if (catF) list = list.filter(a => a.category === catF);
  list.sort((a, b) => new Date(a.replaceDate) - new Date(b.replaceDate));

  const now = new Date();
  const icons = { 'Fleet Vehicles': '🚗', 'Buildings & Facilities': '🏢', 'IT Equipment': '💻', 'Parks & Recreation': '🌳', 'Public Safety': '🚨', 'Roads & Infrastructure': '🛣️', 'Utilities': '⚡', 'Other': '📦' };
  const tlEl = document.getElementById('replacementTimeline');
  if (!list.length) {
    tlEl.innerHTML = '<div class="empty"><div class="empty-icon">📅</div><div class="empty-text">No replacement data to display</div></div>';
  } else {
    tlEl.innerHTML = '<div class="timeline">' + list.map(a => {
      const days = Math.ceil((new Date(a.replaceDate) - now) / (24 * 3600 * 1000));
      const cls = days < 0 ? 'urgent' : days < 365 ? 'soon' : 'planned';
      return `<div class="tl-item ${cls}" onclick="showDetail('${a.id}')" style="cursor:pointer">
        <div class="tl-icon">${icons[a.category] || '📦'}</div>
        <div class="tl-info">
          <div class="tl-name">${a.name}</div>
          <div class="tl-meta">${a.category} · ${a.location || 'No location'} · ${fmtDate(a.replaceDate)}</div>
        </div>
        <div class="tl-cost">${a.replaceCost ? fmtCurrency(a.replaceCost) : '—'}</div>
      </div>`;
    }).join('') + '</div>';
  }

  // Budget summary
  const budgetEl = document.getElementById('budgetSummary');
  if (!list.length) {
    budgetEl.innerHTML = '<div class="empty"><div class="empty-icon">💰</div><div class="empty-text">Add assets to see budget summary</div></div>';
  } else {
    const total = list.reduce((s, a) => s + (a.replaceCost || 0), 0);
    const overdue = list.filter(a => new Date(a.replaceDate) < now).reduce((s, a) => s + (a.replaceCost || 0), 0);
    const within1yr = list.filter(a => { const d = new Date(a.replaceDate); return d >= now && d <= new Date(now.getFullYear() + 1, now.getMonth(), now.getDate()); }).reduce((s, a) => s + (a.replaceCost || 0), 0);
    budgetEl.innerHTML = `
      <div style="display:flex;flex-direction:column;gap:12px">
        <div class="budget-block overdue">
          <div class="budget-label">Overdue / Past Due</div>
          <div class="budget-value">${fmtCurrency(overdue)}</div>
        </div>
        <div class="budget-block soon">
          <div class="budget-label">Within 12 Months</div>
          <div class="budget-value">${fmtCurrency(within1yr)}</div>
        </div>
        <div class="budget-block total">
          <div class="budget-label">Total (Filtered)</div>
          <div class="budget-value">${fmtCurrency(total)}</div>
        </div>
      </div>
    `;
  }
}

function refreshReplacements() {
  // Populate year filter
  const years = [...new Set(assets.filter(a => a.replaceDate).map(a => new Date(a.replaceDate).getFullYear()))].sort();
  const yrEl = document.getElementById('replYearFilter');
  const curYr = yrEl.value;
  yrEl.innerHTML = '<option value="">All Years</option>' + years.map(y => `<option value="${y}"${y == curYr ? ' selected' : ''}>${y}</option>`).join('');

  const catEl = document.getElementById('replCatFilter');
  const curCat = catEl.value;
  const cats = [...new Set(assets.map(a => a.category))].sort();
  catEl.innerHTML = '<option value="">All Categories</option>' + cats.map(c => `<option value="${c}"${c === curCat ? ' selected' : ''}>${c}</option>`).join('');

  renderReplacements();
}

function refreshAlerts() {
  const now = new Date();
  const alerts = [];

  assets.forEach(a => {
    if (a.condition === 'Critical') alerts.push({ level: 'high', icon: '⛔', text: `${a.name} is in CRITICAL condition`, sub: `${a.category} · ${a.location || 'No location'} · Immediate attention required` });
    if (a.condition === 'Poor') alerts.push({ level: 'high', icon: '🔴', text: `${a.name} is in Poor condition`, sub: `${a.category} · ${a.location || 'No location'}` });
    if (a.replaceDate) {
      const days = Math.ceil((new Date(a.replaceDate) - now) / (24 * 3600 * 1000));
      if (days < 0) alerts.push({ level: 'high', icon: '📅', text: `${a.name} replacement is OVERDUE`, sub: `Was due ${fmtDate(a.replaceDate)} · Est. cost: ${fmtCurrency(a.replaceCost)}` });
      else if (days < 180) alerts.push({ level: 'med', icon: '⏰', text: `${a.name} replacement due in ${days} days`, sub: `Due: ${fmtDate(a.replaceDate)} · Est. cost: ${fmtCurrency(a.replaceCost)}` });
      else if (days < 365) alerts.push({ level: 'low', icon: '📋', text: `${a.name} replacement coming up in ${Math.round(days / 30)} months`, sub: `Due: ${fmtDate(a.replaceDate)} · Est. cost: ${fmtCurrency(a.replaceCost)}` });
    }
    if (a.rating <= 2 && a.rating > 0) alerts.push({ level: 'med', icon: '⭐', text: `${a.name} has a low condition rating (${a.rating}/5)`, sub: `${a.category} · Consider scheduling maintenance or replacement` });
  });

  document.getElementById('alertBadge').textContent = alerts.filter(a => a.level === 'high').length || '';
  const alertsEl = document.getElementById('alertsList');
  if (!alerts.length) {
    alertsEl.innerHTML = '<div class="empty"><div class="empty-icon">✅</div><div class="empty-text">No alerts — all assets are in good standing!</div></div>';
  } else {
    alertsEl.innerHTML = '<div class="alert-list">' + alerts.sort((a, b) => { const o = {high:0,med:1,low:2}; return o[a.level] - o[b.level]; }).map(a =>
      `<div class="alert-item ${a.level}"><div class="alert-icon">${a.icon}</div><div><div class="alert-text">${a.text}</div><div class="alert-sub">${a.sub}</div></div></div>`
    ).join('') + '</div>';
  }
}

function refreshAssetFilters() {
  const catEl = document.getElementById('filterCategory');
  const curCat = catEl.value;
  const cats = [...new Set(assets.map(a => a.category))].sort();
  catEl.innerHTML = '<option value="">All Categories</option>' + cats.map(c => `<option value="${c}"${c === curCat ? ' selected' : ''}>${c}</option>`).join('');

  const deptEl = document.getElementById('filterDept');
  if (deptEl) {
    const curDept = deptEl.value;
    // Extract dept codes/names from location field
    const depts = [...new Set(assets.map(a => a.location).filter(Boolean))].sort();
    deptEl.innerHTML = '<option value="">All Departments</option>' + depts.map(d => {
      const label = d.replace(/^\d+-\s*/, '').trim() || d;
      return `<option value="${d}"${d === curDept ? ' selected' : ''}>${label}</option>`;
    }).join('');
  }
}

function refreshAll() {
  refreshDashboard();
  filterAssets();
  refreshAssetFilters();
  refreshProjections();
  refreshReplacements();
  refreshAlerts();
  renderDeptPage();
  refreshBudgetAnalysis();
  renderAuditLog();
}

// ====================== DEPARTMENT SUMMARY ======================
function buildDeptSummary() {
  const map = {};
  assets.forEach(a => {
    const key = a.location || 'Unknown';
    if (!map[key]) map[key] = { name: key, assets: [], totalOrig: 0, totalRepl: 0, conditions: {Good:0,Fair:0,Poor:0,Critical:0}, categories: {} };
    map[key].assets.push(a);
    map[key].totalOrig += a.purchaseCost || 0;
    map[key].totalRepl += a.replaceCost || 0;
    map[key].conditions[a.condition] = (map[key].conditions[a.condition] || 0) + 1;
    map[key].categories[a.category] = (map[key].categories[a.category] || 0) + 1;
  });
  return map;
}

function renderDeptPage() {
  const search = (document.getElementById('deptSearch')?.value || '').toLowerCase();
  const catF = document.getElementById('deptCatFilter')?.value || '';
  const condF = document.getElementById('deptCondFilter')?.value || '';

  const map = buildDeptSummary();
  let depts = Object.values(map);

  // Apply filters
  if (search) depts = depts.filter(d => d.name.toLowerCase().includes(search));
  if (catF) depts = depts.filter(d => d.categories[catF]);
  if (condF) depts = depts.filter(d => d.conditions[condF] > 0);

  // Sort by total replacement cost desc
  depts.sort((a,b) => b.totalRepl - a.totalRepl);

  document.getElementById('deptCount').textContent = `${depts.length} departments`;

  // Top KPIs
  const totalDepts = depts.length;
  const totalAssets = depts.reduce((s,d) => s + d.assets.length, 0);
  const totalRepl = depts.reduce((s,d) => s + d.totalRepl, 0);
  const critDepts = depts.filter(d => (d.conditions.Critical||0) + (d.conditions.Poor||0) > 0).length;
  document.getElementById('deptKpiGrid').innerHTML = `
    <div class="kpi-card gold"><div class="kpi-label">Departments</div><div class="kpi-value">${totalDepts}</div><div class="kpi-sub">Shown in current filter</div><div class="kpi-icon">🏛</div></div>
    <div class="kpi-card teal"><div class="kpi-label">Assets (Filtered)</div><div class="kpi-value">${totalAssets.toLocaleString()}</div><div class="kpi-sub">Across all shown depts</div><div class="kpi-icon">🗂</div></div>
    <div class="kpi-card red"><div class="kpi-label">Depts w/ Poor/Critical</div><div class="kpi-value">${critDepts}</div><div class="kpi-sub">Need attention</div><div class="kpi-icon">⚠️</div></div>
    <div class="kpi-card green"><div class="kpi-label">Total Est. Repl. Cost</div><div class="kpi-value">${fmtCurrency(totalRepl)}</div><div class="kpi-sub">Filtered departments</div><div class="kpi-icon">💰</div></div>
  `;

  if (!depts.length) {
    document.getElementById('deptCardsGrid').innerHTML = '<div class="empty" style="grid-column:1/-1"><div class="empty-icon">🏛</div><div class="empty-text">No departments match your filters.</div></div>';
    return;
  }

  const condColors = { Good:'#27ae60', Fair:'#e8b04a', Poor:'#e67e22', Critical:'#c0392b' };
  const catIcons = { 'Fleet Vehicles':'🚗','Buildings & Facilities':'🏢','IT Equipment':'💻','Parks & Recreation':'🌳','Public Safety':'🚨','Roads & Infrastructure':'🛣️','Utilities':'⚡','Other':'📦' };

  document.getElementById('deptCardsGrid').innerHTML = depts.map(d => {
    const total = d.assets.length;
    const critical = (d.conditions.Critical||0) + (d.conditions.Poor||0);
    const topCat = Object.entries(d.categories).sort((a,b)=>b[1]-a[1])[0];
    const codeMatch = d.name.match(/^(\d+)/);
    const code = codeMatch ? codeMatch[1] : '';
    const deptLabel = d.name.replace(/^\d+-?\s*/,'').trim();

    // Condition bar segments
    const condSegs = ['Good','Fair','Poor','Critical'].map(c => {
      const pct = total > 0 ? ((d.conditions[c]||0)/total*100).toFixed(1) : 0;
      return pct > 0 ? `<div class="dept-cond-seg" style="width:${pct}%;background:${condColors[c]}" title="${c}: ${d.conditions[c]||0}"></div>` : '';
    }).join('');

    const condLegend = ['Good','Fair','Poor','Critical'].filter(c => d.conditions[c]>0).map(c =>
      `<div class="dept-cond-item"><div class="dept-cond-dot" style="background:${condColors[c]}"></div>${d.conditions[c]} ${c}</div>`
    ).join('');

    const critBadge = critical > 0
      ? `<span class="tag tag-critical" style="font-size:10px;margin-left:6px">${critical} ⚠</span>`
      : '';

    return `<div class="dept-card">
      <div class="dept-card-header">
        <div class="dept-name">${deptLabel}${critBadge}</div>
        ${code ? `<div class="dept-code">${code}</div>` : ''}
      </div>
      <div class="dept-stats">
        <div class="dept-stat"><div class="dept-stat-val">${total}</div><div class="dept-stat-lbl">Assets</div></div>
        <div class="dept-stat"><div class="dept-stat-val" style="color:${critical>0?'#c0392b':'#27ae60'}">${critical}</div><div class="dept-stat-lbl">Poor/Critical</div></div>
        <div class="dept-stat"><div class="dept-stat-val" style="font-size:13px">${topCat ? (catIcons[topCat[0]]||'📦') : '—'}</div><div class="dept-stat-lbl" style="font-size:9px">${topCat ? topCat[0].split(' ')[0] : '—'}</div></div>
      </div>
      <div class="dept-cond-bar">${condSegs || '<div style="width:100%;background:#e8ecf3;border-radius:4px"></div>'}</div>
      <div class="dept-cond-legend">${condLegend}</div>
      <div class="dept-footer">
        <div>
          <div class="dept-cost">${fmtCurrency(d.totalRepl)}</div>
          <div class="dept-cost-lbl">Est. replacement cost</div>
        </div>
        <button class="dept-view-btn" onclick="viewDeptAssets('${d.name.replace(/'/g,"\\'")}')">View Assets →</button>
      </div>
    </div>`;
  }).join('');
}

function viewDeptAssets(deptName) {
  // Switch to All Assets tab and filter by department
  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  document.querySelectorAll('.nav-tab').forEach(t => t.classList.remove('active'));
  document.getElementById('page-assets').classList.add('active');
  document.querySelectorAll('.nav-tab')[1].classList.add('active');
  document.getElementById('searchInput').value = deptName;
  filterAssets();
}

function openExport() {
  if (!assets.length) { alert('No assets to export.'); return; }
  const headers = ['Asset ID','Name','Category','Location','Condition','Rating','Purchase Date','Purchase Cost','Replacement Date','Est. Replacement Cost','Status','Notes'];
  const rows = assets.map(a => [a.assetId,a.name,a.category,a.location,a.condition,a.rating,a.purchaseDate,a.purchaseCost,a.replaceDate,a.replaceCost,a.status,a.notes].map(v => `"${v || ''}"`).join(','));
  const csv = [headers.join(','), ...rows].join('\n');
  const blob = new Blob([csv], {type:'text/csv'});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a'); a.href = url; a.download = 'spartanburg_assets.csv'; a.click();
  URL.revokeObjectURL(url);
}

// ====================== IMPORT CSV ======================
function importCSV(event) {
  const file = event.target.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = function(e) {
    const lines = e.target.result.split('\n').filter(l => l.trim());
    if (!lines.length) { alert('CSV file appears to be empty.'); return; }

    // Detect if first line is a header row
    const firstLine = lines[0].toLowerCase();
    const hasHeader = firstLine.includes('asset') || firstLine.includes('name') || firstLine.includes('category');
    const dataLines = hasHeader ? lines.slice(1) : lines;

    let imported = 0, skipped = 0, updated = 0;
    const errors = [];

    dataLines.forEach((line, idx) => {
      if (!line.trim()) return;
      // Parse CSV respecting quoted fields
      const cols = [];
      let cur = '', inQ = false;
      for (let i = 0; i < line.length; i++) {
        if (line[i] === '"') { inQ = !inQ; }
        else if (line[i] === ',' && !inQ) { cols.push(cur.trim()); cur = ''; }
        else { cur += line[i]; }
      }
      cols.push(cur.trim());

      const name = (cols[1] || '').replace(/^"|"$/g, '').trim();
      const category = (cols[2] || '').replace(/^"|"$/g, '').trim();
      const condition = (cols[8] || 'Fair').replace(/^"|"$/g, '').trim();

      if (!name) { skipped++; return; }

      const validConditions = ['Good', 'Fair', 'Poor', 'Critical'];
      const validCategories = ['Fleet Vehicles', 'Buildings & Facilities', 'IT Equipment', 'Parks & Recreation', 'Public Safety', 'Roads & Infrastructure', 'Utilities', 'Other'];
      const finalCondition = validConditions.includes(condition) ? condition : 'Fair';
      const finalCategory = category || 'Other';

      const assetId = (cols[0] || '').replace(/^"|"$/g, '').trim() || genId();
      const rating = parseInt(cols[9]) || 3;
      const status = (cols[10] || 'Active').replace(/^"|"$/g, '').trim();

      // Parse currency fields — strip $, commas
      const parseMoney = v => parseFloat((v || '0').replace(/[$,\s"]/g, '')) || 0;
      const parseDate = v => {
        const s = (v || '').replace(/^"|"$/g, '').trim();
        if (!s) return '';
        const d = new Date(s);
        if (isNaN(d)) return '';
        return d.toISOString().split('T')[0];
      };

      const asset = {
        id: genId(),
        assetId,
        name,
        category: finalCategory,
        location: (cols[3] || '').replace(/^"|"$/g, '').trim(),
        purchaseDate: parseDate(cols[4]),
        purchaseCost: parseMoney(cols[5]),
        replaceDate: parseDate(cols[6]),
        replaceCost: parseMoney(cols[7]),
        condition: finalCondition,
        rating: Math.min(5, Math.max(1, rating)),
        status: ['Active','Inactive','Pending Replacement'].includes(status) ? status : 'Active',
        usefulLife: parseInt(cols[11]) || 0,
        notes: (cols[12] || '').replace(/^"|"$/g, '').trim(),
        updatedAt: new Date().toISOString()
      };

      // Update if same assetId exists, otherwise add
      const existingIdx = assets.findIndex(a => a.assetId === assetId && assetId !== '');
      if (existingIdx >= 0) { assets[existingIdx] = { ...assets[existingIdx], ...asset, id: assets[existingIdx].id }; updated++; }
      else { assets.unshift(asset); imported++; }
    });

    saveData();
    logBulkImport(imported, updated);
    refreshAll();
    event.target.value = '';

    const msg = [`✅ Import complete!`, ``, `• ${imported} new assets added`, `• ${updated} existing assets updated`, `• ${skipped} rows skipped (missing name)`, ``, `Review the "All Assets" tab to verify.`].join('\n');
    alert(msg);
  };
  reader.readAsText(file);
}

// ====================== BUDGET ANALYSIS ======================
function refreshBudgetAnalysis() {
  if (!document.getElementById('budgetKpiGrid')) return;

  const now = new Date();
  const currentYear = now.getFullYear();

  // KPIs
  const totalReplCost = assets.reduce((sum, a) => sum + (a.replaceCost || 0), 0);
  const overdueAssets = assets.filter(a => a.replaceDate && new Date(a.replaceDate) < now);
  const overdueCost = overdueAssets.reduce((sum, a) => sum + (a.replaceCost || 0), 0);
  const in5yr = assets.filter(a => {
    if (!a.replaceDate) return false;
    const year = new Date(a.replaceDate).getFullYear();
    return year >= currentYear && year <= currentYear + 5;
  });
  const in5yrCost = in5yr.reduce((sum, a) => sum + (a.replaceCost || 0), 0);
  const criticalCost = assets.filter(a => a.condition === 'Critical' || a.condition === 'Poor').reduce((sum, a) => sum + (a.replaceCost || 0), 0);
  const nearTermCost = assets.filter(a => a.replaceDate && new Date(a.replaceDate) <= new Date(currentYear + 1, now.getMonth(), now.getDate())).reduce((sum, a) => sum + (a.replaceCost || 0), 0);

  document.getElementById('budgetKpiGrid').innerHTML = `
    <div class="kpi-card red"><div class="kpi-label">Overdue Replacement Cost</div><div class="kpi-value">${fmtCurrency(overdueCost)}</div><div class="kpi-sub">${overdueAssets.length} assets past due date</div><div class="kpi-icon">⏰</div></div>
    <div class="kpi-card gold"><div class="kpi-label">5-Year Capital Need</div><div class="kpi-value">${fmtCurrency(in5yrCost)}</div><div class="kpi-sub">${in5yr.length} assets, ${currentYear}–${currentYear + 5}</div><div class="kpi-icon">📅</div></div>
    <div class="kpi-card teal"><div class="kpi-label">Poor/Critical Asset Cost</div><div class="kpi-value">${fmtCurrency(criticalCost)}</div><div class="kpi-sub">Total for poor/critical condition assets</div><div class="kpi-icon">⚠️</div></div>
    <div class="kpi-card green"><div class="kpi-label">Near-Term 12-Month Cost</div><div class="kpi-value">${fmtCurrency(nearTermCost)}</div><div class="kpi-sub">Assets due within the next year</div><div class="kpi-icon">🕒</div></div>
  `;

  // Annual chart (10 years)
  const years = Array.from({length: 10}, (_, i) => currentYear + i);
  const yearData = {};
  years.forEach(y => { yearData[y] = 0; });
  assets.forEach(a => {
    if (!a.replaceDate || !a.replaceCost) return;
    const year = new Date(a.replaceDate).getFullYear();
    if (yearData[year] !== undefined) yearData[year] += a.replaceCost;
  });
  const maxY = Math.max(...Object.values(yearData), 1);
  const yearRows = years.map(year => {
    const items = assets.filter(a => a.replaceDate && new Date(a.replaceDate).getFullYear() === year);
    return {
      year,
      total: yearData[year],
      count: items.length,
      overdue: items.filter(a => new Date(a.replaceDate) < now).length,
      poor: items.filter(a => a.condition === 'Critical' || a.condition === 'Poor').length
    };
  });
  document.getElementById('budgetAnnualChart').innerHTML = `
    <div class="budget-grid">
      ${yearRows.map(row => {
        const pct = row.total ? (row.total / maxY) * 100 : 0;
        return `<div class="budget-year-card">
          <div class="budget-year-head">
            <div>
              <div class="budget-year">${row.year}</div>
              <div class="budget-year-sub">${row.count} asset${row.count === 1 ? '' : 's'}</div>
            </div>
            <div class="budget-year-value">${row.total ? fmtCurrency(row.total) : '—'}</div>
          </div>
          <div class="budget-year-track"><div class="budget-year-fill ${row.overdue ? 'urgent' : row.poor ? 'soon' : 'planned'}" style="width:${Math.max(pct, row.total ? 8 : 0)}%"></div></div>
          <div class="budget-year-foot">${row.overdue ? `${row.overdue} overdue` : row.poor ? `${row.poor} high risk` : getYearLabel(currentYear, row.year)}</div>
        </div>`;
      }).join('')}
    </div>`;

  // Condition cost breakdown
  const condCosts = { Good: 0, Fair: 0, Poor: 0, Critical: 0 };
  const condCounts = { Good: 0, Fair: 0, Poor: 0, Critical: 0 };
  assets.forEach(a => {
    if (condCosts[a.condition] !== undefined) {
      condCosts[a.condition] += (a.replaceCost || 0);
      condCounts[a.condition]++;
    }
  });
  const condColors = { Good:'#27ae60', Fair:'#e8b04a', Poor:'#e67e22', Critical:'#c0392b' };
  const grandCondTotal = Object.values(condCosts).reduce((sum, value) => sum + value, 0) || 1;
  const condOrder = ['Critical', 'Poor', 'Fair', 'Good'];
  document.getElementById('budgetConditionBreakdown').innerHTML = `
    <div class="condition-stack">
      <div class="condition-track">
        ${condOrder.map(c => {
          const pct = ((condCosts[c] / grandCondTotal) * 100).toFixed(1);
          return `<div class="condition-seg ${c.toLowerCase()}" style="width:${pct}%"></div>`;
        }).join('')}
      </div>
      <div class="condition-list">
        ${condOrder.map(c => {
          const pct = ((condCosts[c] / grandCondTotal) * 100).toFixed(1);
          return `<div class="condition-row">
            <div class="condition-head">
              <span class="condition-name" style="color:${condColors[c]}">${c}</span>
              <span class="condition-meta">${condCounts[c]} assets · ${fmtCurrency(condCosts[c])}</span>
            </div>
            <div class="condition-track small"><div class="condition-fill" style="width:${pct}%;background:${condColors[c]};"></div></div>
          </div>`;
        }).join('')}
      </div>
    </div>`;

  // Top 20 most costly
  const top20 = [...assets]
    .filter(a => (a.replaceCost || 0) > 0)
    .sort((a, b) => (b.replaceCost || 0) - (a.replaceCost || 0))
    .slice(0, 20);
  const maxTop20 = top20[0]?.replaceCost || 1;
  document.getElementById('budgetTop20Body').innerHTML = top20.map((a, i) => {
    const status = getReplacementStatus(a, now);
    const costPct = ((a.replaceCost || 0) / maxTop20) * 100;
    return `<tr onclick="showDetail('${a.id}')" style="cursor:pointer">
      <td style="font-family:'DM Mono',monospace;font-weight:700;color:var(--text-light)">#${i + 1}</td>
      <td><strong>${a.name}</strong><div class="row-mini-bar"><div class="row-mini-fill" style="width:${Math.max(costPct, 8)}%"></div></div></td>
      <td style="font-size:12px;color:var(--text-mid)">${(a.location || '').replace(/^\d+-\s*/, '')}</td>
      <td><span class="tag tag-blue" style="font-size:10px">${a.category}</span></td>
      <td>${condTag(a.condition)}</td>
      <td><span class="tag ${status.level === 'urgent' ? 'tag-critical' : status.level === 'soon' ? 'tag-poor' : 'tag-good'}">${status.label}</span> <span style="font-size:12px;color:${status.level === 'urgent' ? 'var(--red)' : 'var(--text)'}">${a.replaceDate ? fmtDate(a.replaceDate) : '—'}</span></td>
      <td style="font-family:'DM Mono',monospace;font-weight:700;color:var(--teal);font-size:14px">${fmtCurrency(a.replaceCost)}</td>
    </tr>`;
  }).join('');

  // Dept ranking
  const deptTotals = {};
  const deptCounts = {};
  assets.forEach(a => {
    const department = (a.location || 'Unknown').replace(/^\d+-\s*/, '').trim() || 'Unknown';
    deptTotals[department] = (deptTotals[department] || 0) + (a.replaceCost || 0);
    deptCounts[department] = (deptCounts[department] || 0) + 1;
  });
  const deptEntries = Object.entries(deptTotals).sort((a, b) => b[1] - a[1]).slice(0, 15);
  const maxDept = deptEntries[0]?.[1] || 1;
  document.getElementById('budgetDeptRanking').innerHTML = deptEntries.map(([name, cost], i) => {
    const pct = (cost / maxDept) * 100;
    return `<div class="budget-rank-row">
      <div class="budget-rank-index">#${i + 1}</div>
      <div class="budget-rank-body">
        <div class="budget-rank-head">
          <span class="budget-rank-name">${name}</span>
          <span class="budget-rank-cost">${fmtCurrency(cost)}</span>
        </div>
        <div class="budget-rank-track"><div class="budget-rank-fill" style="width:${Math.max(pct, 8)}%"></div></div>
        <div class="budget-rank-meta">${deptCounts[name]} assets · ${((cost / (Object.values(deptTotals).reduce((sum, value) => sum + value, 0) || 1)) * 100).toFixed(1)}% of total</div>
      </div>
    </div>`;
  }).join('');
}

// ====================== EXPORT TO EXCEL ======================
function exportToExcel() {
  if (!assets.length) { alert('No assets to export.'); return; }
  if (typeof XLSX === 'undefined') { alert('Excel library not loaded. Please check your internet connection.'); return; }

  const headers = ['Asset ID','Name','Category','Location / Department','Condition','Rating (1-5)','Purchase Date','Purchase Cost ($)','Replacement Date','Est. Replacement Cost ($)','Status','Notes'];
  const rows = assets.map(a => [
    a.assetId, a.name, a.category, a.location, a.condition, a.rating,
    a.purchaseDate, a.purchaseCost||0, a.replaceDate, a.replaceCost||0, a.status, a.notes
  ]);

  // Summary sheet data
  const now = new Date();
  const condCounts = {Good:0,Fair:0,Poor:0,Critical:0};
  const catCosts = {};
  assets.forEach(a => {
    if(condCounts[a.condition]!==undefined) condCounts[a.condition]++;
    catCosts[a.category] = (catCosts[a.category]||0) + (a.replaceCost||0);
  });
  const summaryData = [
    ['City of Spartanburg — Asset Management Summary'],
    ['Generated:', now.toLocaleDateString()],
    [],
    ['OVERVIEW'],
    ['Total Assets', assets.length],
    ['Total Est. Replacement Value', assets.reduce((s,a)=>s+(a.replaceCost||0),0)],
    [],
    ['CONDITION BREAKDOWN'],
    ['Good', condCounts.Good],
    ['Fair', condCounts.Fair],
    ['Poor', condCounts.Poor],
    ['Critical', condCounts.Critical],
    [],
    ['REPLACEMENT COST BY CATEGORY'],
    ...Object.entries(catCosts).sort((a,b)=>b[1]-a[1]).map(([k,v])=>[k,v])
  ];

  const wb = XLSX.utils.book_new();

  // Assets sheet
  const wsData = [headers, ...rows];
  const ws = XLSX.utils.aoa_to_sheet(wsData);
  ws['!cols'] = [10,30,20,25,10,8,12,15,12,18,18,40].map(w=>({wch:w}));
  XLSX.utils.book_append_sheet(wb, ws, 'All Assets');

  // Summary sheet
  const wsSummary = XLSX.utils.aoa_to_sheet(summaryData);
  wsSummary['!cols'] = [{wch:35},{wch:20}];
  XLSX.utils.book_append_sheet(wb, wsSummary, 'Summary');

  XLSX.writeFile(wb, `Spartanburg_Assets_${now.toISOString().split('T')[0]}.xlsx`);
}

